const item = $input.first().json;
const nd = $('Set — Normalizar Input').first().json;
let rc = '';
if (item.results && Array.isArray(item.results)) {
  rc = `RESPOSTA DIRETA: ${item.answer || 'N/A'}\n\nFONTES:\n`;
  item.results.forEach((r, i) => {
    rc += `\n[${i+1}] TÍTULO: ${r.title}\nCONTEÚDO: ${r.content?.substring(0, 600)}\nURL: ${r.url}\n`;
  });
} else {
  const c = typeof item === 'string' ? item : (item.data || item.text || JSON.stringify(item));
  rc = `CONTEÚDO DA URL:\n${c.toString().substring(0, 6000)}`;
}
return [{ json: { ...nd, research_content: rc.substring(0, 7000), research_ready: true } }];

