const item = $input.first().json;
const nd = $('Set — Normalizar Input').first().json;
const rep = $('HTTP — Replicate Flux Iniciar').first().json;
let content = {};
try {
  const ao = item.output || item.text || JSON.stringify(item);
  const cl = ao.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const m = cl.match(/\{[\s\S]*\}/);
  content = m ? JSON.parse(m[0]) : {};
} catch(e) {
  content = { linkedin: { text: 'Erro ao gerar', hashtags: [] }, instagram: { caption: 'Erro', stories: [], hashtags: [] }, meta_strategy: { predicted_engagement_score: 5, best_post_time: '09:00' } };
}
return [{ json: { session_id: nd.session_id, topic: nd.topic, niche: nd.niche, tone: nd.tone, language: nd.language, brand_voice: nd.brand_voice, linkedin_post: content.linkedin || {}, instagram_post: content.instagram || {}, meta_strategy: content.meta_strategy || {}, image_prompt_en: content.image_prompt_en || '', image_prediction_id: rep.id || '', image_status: rep.status || 'starting', created_at: nd.created_at, status: 'generating' } }];

const r = $input.first().json;
const c = $('Code — Parsear Conteúdo AI').first().json;
let imageUrl = null;
if (r.output) { imageUrl = Array.isArray(r.output) ? r.output[0] : r.output; }
const lt = c.linkedin_post.text || '';
const lh = (c.linkedin_post.hashtags || []).map(h => `#${h.replace('#', '')}`).join(' ');
const ic = c.instagram_post.caption || '';
const ih = (c.instagram_post.hashtags || []).map(h => `#${h.replace('#', '')}`).join(' ');
return [{ json: { ...c, linkedin_post: { ...c.linkedin_post, text: lh ? `${lt}\n\n${lh}` : lt }, instagram_post: { ...c.instagram_post, caption: ih ? `${ic}\n\n${ih}` : ic }, image_url: imageUrl, image_ready: !!imageUrl, status: 'ready_to_publish', predicted_score: c.meta_strategy?.predicted_engagement_score || 7 } }];

